  if (!tested || isNaN(tested) || isNaN(passed)) return null;
  if (passed > tested) return null;
  return {
    passRate:   ((passed / tested) * 100).toFixed(1),
    rejectRate: (((tested - passed) / tested) * 100).toFixed(1),
  };
}

