    const row = rows[id];
    if (row) {
      const value = field === "aspPerKg" ? row.aspPerKg : row.quantityKg;
      const formatted = formatDisplayValue(value);
      setDisplayValues(prev => ({
        ...prev,
        [id]: {
          ...prev[id],
          [field]: formatted
        }
      }));
