      if (originalSale) {
        setRows((prev) => ({
          ...prev,
          [productId]: {
            ...prev[productId],
            market: originalSale.market,
            aspPerKg: Number(originalSale.asp_per_kg),
            quantityKg: Number(originalSale.quantity_kg),
            totalSalesUSD: Number(originalSale.total_sales_usd),
            isReadOnly: true,
          },
        }));
      } else {
        // If no original sale, reset to empty state

function handleReset() {
    if (cache.current[dateISO]) {
      applyRows(products, cache.current[dateISO]);
    } else {
      setRows(emptyRows(products));
    }
    setUnlockedIds(new Set());
    setStatus("idle");
    setStatusMsg("");
  }

async function handleSave(e: React.FormEvent) {
    e.preventDefault();

    // Determine which rows to save:
    // 1. Any unlocked row (even if values are zero)
    // 2. Any editable row that has values > 0
    const rowsToSave = Object.values(rows).filter((r) => {
      if (unlockedIds.has(r.product_id)) return true;
      if (!r.isReadOnly && r.aspPerKg > 0 && r.quantityKg > 0) return true;
      return false;
    });

    if (rowsToSave.length === 0) {
      setStatus("error");
      setStatusMsg("Please enter ASP and quantity for at least one product, or unlock a saved entry to update it.");
      return;
    }

    const payload = rowsToSave.map((r) => ({
      product_id:  r.product_id,
      market:      r.market,
      asp_per_kg:  r.aspPerKg,
      quantity_kg: r.quantityKg,
    }));

interface TradeRow {
  product_id: number;
  market: "Export" | "Local";
  counterparty: string;
  price_per_kg: number;
  quantity_kg: number;
  total_value: number;
  isReadOnly: boolean;
}

interface Product {
  id: number;
  name: string;
  unit?: string;
}

interface TradingInputFormProps {
  products: Product[];
  loading: boolean;
  onSaved: () => void;
}

function getTodayISO() {
  return new Date().toLocaleDateString("en-CA");
}

function dateToISO(d: Date) {
  return d.toLocaleDateString("en-CA");
}

function isoToDate(iso: string) {
  const [y, m, d] = iso.split("-").map(Number);
  return new Date(y, m - 1, d);
}

function fmtUSD(n: number) {
  return "$" + n.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
}

function formatDisplayValue(value: number | string): string {
  if (value === "" || value === null || value === undefined) return "";
  const num = typeof value === 'string' ? parseFloat(value) : value;
  if (isNaN(num)) return String(value);
  if (Number.isInteger(num)) {
    return num.toLocaleString();
  } else {
    return num.toLocaleString(undefined, {
      minimumFractionDigits: 2,
      maximumFractionDigits: 2
    });
  }
}

function emptyRows(products: Product[]): Record<number, TradeRow> {
  return Object.fromEntries(
    products.map((p) => [
      p.id,
      {
        product_id: p.id,
        market: "Export" as "Export",
        counterparty: "",
        price_per_kg: 0,
        quantity_kg: 0,
        total_value: 0,
        isReadOnly: false,
      },
    ])
  );
}

function populateRows(products: Product[], trades: any[]): Record<number, TradeRow> {
  const tradesMap = new Map(trades.map((t) => [t.product_id, t]));
  return Object.fromEntries(
    products.map((p) => {
      const existing = tradesMap.get(p.id);
      const hasData = existing && (Number(existing.price_per_kg) > 0 || Number(existing.quantity_kg) > 0);
      return [
        p.id,
        {
          product_id: p.id,
          market: existing?.market ?? "Export",
          counterparty: existing?.counterparty ?? "",
          price_per_kg: existing ? Number(existing.price_per_kg) : 0,
          quantity_kg: existing ? Number(existing.quantity_kg) : 0,
          total_value: existing ? Number(existing.total_value) : 0,
          isReadOnly: !!hasData,
        },
      ];
    })
  );
}

